SELECT AVG(market_cap) AS average_market_cap
FROM companies
WHERE country = 'Australia' AND sector = '0';

SELECT SUM(market_cap) AS total_market_cap
FROM companies
WHERE sector = 'Technology';

SELECT SUM(market_cap) AS total_market_cap
FROM companies
WHERE sector = 'Healthcare';

SELECT c.name, c.market_cap
FROM companies c
ORDER BY c.market_cap DESC;
